# Variables and functions: snake_case
user_name = "alice"
def calculate_total(items):
    return sum(items)

# Classes: PascalCase
class UserAccount:
    pass

# Constants: UPPER_CASE
MAX_RETRIES = 3
DEFAULT_TIMEOUT = 30

# Internal or protected: _leading_underscore
_internal_cache = {}

# Strongly private (name-mangled inside a class): __double_underscore
class A:
    def __init__(self):
        self.__secret = 42

a = A()
print(dir(a))    # __secret becomes _A__secret

# Dunder methods: __name__   reserved by Python, do not invent
class Point:
    def __init__(self, x): self.x = x
    def __repr__(self):    return f"Point({self.x})"
